import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as a,c as l,e as r}from"./chunks/vendor-mermaid.BXjKBAcr.js";const f=JSON.parse('{"title":"Nepal Tax Facts 2081/82","description":"Quick reference card for tax rates, thresholds, and deductions.","frontmatter":{"title":"Nepal Tax Facts 2081/82","description":"Quick reference card for tax rates, thresholds, and deductions.","icon":"📊","parent":"Resources|/resources/","image":"/images/headers/service-tax.jpg","sidebar":false,"head":[["meta",{"property":"og:image","content":"https://arthaadvisory.com.np/images/headers/service-tax.jpg"}],["meta",{"property":"og:title","content":"Nepal Tax Facts 2081/82 | Artha Advisory"}],["meta",{"property":"og:description","content":"Quick reference card for tax rates, thresholds, and deductions."}],["meta",{"name":"description","content":"Quick reference card for tax rates, thresholds, and deductions."}]]},"headers":[],"relativePath":"resources/guides/tax-facts-2081-82.md","filePath":"resources/guides/tax-facts-2081-82.md"}'),n={name:"resources/guides/tax-facts-2081-82.md"};function s(i,t,o,d,c,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="tax-facts-2081-82-2024-25" tabindex="-1">Tax Facts 2081/82 (2024/25) <a class="header-anchor" href="#tax-facts-2081-82-2024-25" aria-label="Permalink to &quot;Tax Facts 2081/82 (2024/25)&quot;">​</a></h1><p><em>A pocket guide to the rates applicable for the current Income Year.</em></p><h2 id="🧑-individual-income-tax-slabs-married-couple" tabindex="-1">🧑 Individual Income Tax Slabs (Married Couple) <a class="header-anchor" href="#🧑-individual-income-tax-slabs-married-couple" aria-label="Permalink to &quot;🧑 Individual Income Tax Slabs (Married Couple)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Taxable Income (NPR)</th><th style="text-align:left;">Rate</th></tr></thead><tbody><tr><td style="text-align:left;">First 6,00,000</td><td style="text-align:left;">1% (SST)</td></tr><tr><td style="text-align:left;">Next 2,00,000</td><td style="text-align:left;">10%</td></tr><tr><td style="text-align:left;">Next 3,00,000</td><td style="text-align:left;">20%</td></tr><tr><td style="text-align:left;">Next 9,00,000</td><td style="text-align:left;">30%</td></tr><tr><td style="text-align:left;">Next 30,00,000</td><td style="text-align:left;">36% (Includes Surcharge)</td></tr><tr><td style="text-align:left;">Above 50,00,000</td><td style="text-align:left;">39% (Includes Surcharge)</td></tr></tbody></table><p><em>(For Unmarried individuals, the first slab is 5,00,000)</em></p><h2 id="🏢-corporate-tax-rates" tabindex="-1">🏢 Corporate Tax Rates <a class="header-anchor" href="#🏢-corporate-tax-rates" aria-label="Permalink to &quot;🏢 Corporate Tax Rates&quot;">​</a></h2><ul><li><strong>Normal Trading/Service:</strong> 25%</li><li><strong>Manufacturing:</strong> 20%</li><li><strong>Banks &amp; Financial Institutions:</strong> 30%</li><li><strong>Tobacco/Liquor/Casino:</strong> 30%</li><li><strong>SME (Turnover &lt; 1 Cr):</strong> Presumptive Tax (Specific Amounts)</li></ul><h2 id="🧾-withholding-tax-tds-rates" tabindex="-1">🧾 Withholding Tax (TDS) Rates <a class="header-anchor" href="#🧾-withholding-tax-tds-rates" aria-label="Permalink to &quot;🧾 Withholding Tax (TDS) Rates&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Payment Type</th><th style="text-align:left;">TDS Rate</th><th style="text-align:left;">Section</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Rent (House/Land)</strong></td><td style="text-align:left;">10%</td><td style="text-align:left;">Sec 88</td></tr><tr><td style="text-align:left;"><strong>Rent (Vehicle/Plant)</strong></td><td style="text-align:left;">10% (Indiv) / 1.5% (VAT Entity)</td><td style="text-align:left;">Sec 88</td></tr><tr><td style="text-align:left;"><strong>Service Fee (Consulting)</strong></td><td style="text-align:left;">15% (Gen) / 1.5% (VAT Entity)</td><td style="text-align:left;">Sec 88</td></tr><tr><td style="text-align:left;"><strong>Interest (Bank Deposit)</strong></td><td style="text-align:left;">5% (Natural Person) / 15% (Entity)</td><td style="text-align:left;">Sec 88</td></tr><tr><td style="text-align:left;"><strong>Dividend</strong></td><td style="text-align:left;">5%</td><td style="text-align:left;">Sec 88</td></tr><tr><td style="text-align:left;"><strong>Meeting Allowance</strong></td><td style="text-align:left;">15%</td><td style="text-align:left;">Sec 88</td></tr><tr><td style="text-align:left;"><strong>Contract ( &gt; 50k)</strong></td><td style="text-align:left;">1.5%</td><td style="text-align:left;">Sec 89</td></tr></tbody></table><h2 id="📉-common-deductions-allowed" tabindex="-1">📉 Common Deductions Allowed <a class="header-anchor" href="#📉-common-deductions-allowed" aria-label="Permalink to &quot;📉 Common Deductions Allowed&quot;">​</a></h2><ul><li><strong>Retirement Fund:</strong> Lower of: (1/3rd of Income) OR (300,000) OR (Actual Contribution).</li><li><strong>Life Insurance:</strong> Actual premium or 40,000.</li><li><strong>Medical Insurance:</strong> Actual premium or 20,000.</li><li><strong>Remote Area Allowance:</strong> Range from 10,000 to 50,000 depending on district.</li></ul><hr><blockquote><p><em>Rates are subject to changes in the Finance Act. Last updated: Shrawan 2081.</em></p></blockquote>',13)])])}const h=e(n,[["render",s]]);export{f as __pageData,h as default};
